#include <iostream>
#include <utility>

class DynArray
{
    int* m_data{};
    int m_size{};

public:
    DynArray(int size)
        : m_data{ new int[size]{} }, m_size{ size } {}

    DynArray(DynArray&& src) noexcept
        : m_data{ src.m_data }, m_size{ src.m_size }
    {
        src.m_data = nullptr;
        src.m_size = 0;
    }

    ~DynArray() { delete[] m_data; }

    DynArray(const DynArray&) = delete;
    DynArray& operator=(const DynArray&) = delete;
    DynArray& operator=(DynArray&&) = delete;

    int size() const { return m_size; }
};

class Holder
{
    DynArray m_arr;

public:
    Holder(DynArray&& arr)
        : m_arr{ std::move(arr) } {}

    int size() const { return m_arr.size(); }
};

int main()
{
    int n{};
    std::cin >> n;

    DynArray arr{ n };

    Holder h{ std::move(arr) };

    std::cout << "source: " << arr.size() << '\n';
    std::cout << "holder: " << h.size() << '\n';

    return 0;
}

