#include <iostream>
#include <utility>

class Buffer
{
    int* m_data{};
    int m_size{};
public:
    Buffer(int size) : m_data{ new int[size]{} }, m_size{ size } {}
    Buffer(Buffer&& src) noexcept : m_data{ src.m_data }, m_size{ src.m_size }
    { src.m_data = nullptr; src.m_size = 0; }
    Buffer& operator=(Buffer&& src) noexcept {
        if (this != &src) {
            delete[] m_data;
            m_data = src.m_data; m_size = src.m_size;
            src.m_data = nullptr; src.m_size = 0;
        }
        return *this;
    }
    ~Buffer() { delete[] m_data; }
    Buffer(const Buffer&) = delete;
    Buffer& operator=(const Buffer&) = delete;
    int size() const { return m_size; }
};

void swapBuffers(Buffer& a, Buffer& b)
{
    Buffer temp{ std::move(a) };
    a = std::move(b);
    b = std::move(temp);
}

int main()
{
    int sizeA{};
    int sizeB{};
    std::cin >> sizeA >> sizeB;

    Buffer a{ sizeA };
    Buffer b{ sizeB };

    std::cout << "before: " << a.size() << ' ' << b.size() << '\n';
    swapBuffers(a, b);
    std::cout << "after: " << a.size() << ' ' << b.size() << '\n';

    return 0;
}
